def best_matches_in_quran(query, topn=10):
    scores=[]
    for a in quran_data:
        text = a.get('ayah_text', '')
        if not text:
            continue
        score = combined_similarity(text, query)
        if score>0:
            scores.append((score, a, text))
    scores.sort(reverse=True, key=lambda x:x[0])
    return scores[:topn]
